1	// Package replicate implements relay-only source-authoritative replication.
2	package replicate
3	
4	import (
5		"context"
6		"fmt"
7		"io"
8	
9		"github.com/go-git/go-git/v6/plumbing"
10	
11		"github.com/soph/git-sync/internal/convert"
12		"github.com/soph/git-sync/internal/gitproto"
13		"github.com/soph/git-sync/internal/planner"
14	)
15	
16	// Params holds the inputs for a replication relay execution.
17	type Params struct {
18		SourceConn    *gitproto.Conn
19		SourceService interface {
20			FetchPack(context.Context, *gitproto.Conn, map[plumbing.ReferenceName]gitproto.DesiredRef, map[plumbing.ReferenceName]plumbing.Hash) (io.ReadCloser, error)
21		}
22		TargetPusher interface {
23			PushPack(context.Context, []gitproto.PushCommand, io.ReadCloser) error
24			PushCommands(context.Context, []gitproto.PushCommand) error
25		}
26		DesiredRefs  map[plumbing.ReferenceName]planner.DesiredRef
27		TargetRefs   map[plumbing.ReferenceName]plumbing.Hash
28		PushPlans    []planner.BranchPlan
29		MaxPackBytes int64
30	}
31	
32	// Result holds the outcome of a replication relay.
33	type Result struct {
34		Relay       bool
35		RelayMode   string
36		RelayReason string
37	}
38	
39	// Execute runs relay-only replication. Create/update refs are pushed via pack
40	// relay and deletes are sent afterwards as ref-only commands.
41	func Execute(ctx context.Context, p Params) (Result, error) {
42		if p.TargetPusher == nil {
43			return Result{}, fmt.Errorf("replicate strategy requires TargetPusher")
44		}
45	
46		updatePlans := make([]planner.BranchPlan, 0, len(p.PushPlans))
47		deletePlans := make([]planner.BranchPlan, 0, len(p.PushPlans))
48		for _, plan := range p.PushPlans {
49			switch plan.Action {
50			case planner.ActionCreate, planner.ActionUpdate:
51				updatePlans = append(updatePlans, plan)
52			case planner.ActionDelete:
53				deletePlans = append(deletePlans, plan)
54			default:
55				return Result{}, fmt.Errorf("replicate strategy does not support %s actions", plan.Action)
56			}
57		}
58	
59		if len(updatePlans) > 0 {
60			desired := convert.DesiredRefsForPlans(p.DesiredRefs, updatePlans)
61			packReader, err := p.SourceService.FetchPack(ctx, p.SourceConn, desired, p.TargetRefs)
62			if err != nil {
63				return Result{}, fmt.Errorf("fetch source pack: %w", err)
64			}
65			packReader = gitproto.LimitPackReader(packReader, p.MaxPackBytes)
66			packReader = closeOnce(packReader)
67			if err := p.TargetPusher.PushPack(ctx, convert.PlansToPushCommands(updatePlans), packReader); err != nil {
68				_ = packReader.Close()
69				return Result{}, fmt.Errorf("push target refs: %w", err)
70			}
71			_ = packReader.Close()
72		}
73	
74		if len(deletePlans) > 0 {
75			if err := p.TargetPusher.PushCommands(ctx, convert.PlansToPushCommands(deletePlans)); err != nil {
76				return Result{}, fmt.Errorf("delete target refs: %w", err)
77			}
78		}
79	
80		return Result{Relay: true, RelayMode: "replicate", RelayReason: "replicate-overwrite-relay"}, nil
81	}
82	
83	type closeOnceReadCloser struct {
84		io.ReadCloser
85		closed bool
86	}
87	
88	func (c *closeOnceReadCloser) Close() error {
89		if c.closed {
90			return nil
91		}
92		c.closed = true
93		return c.ReadCloser.Close()
94	}
95	
96	func closeOnce(rc io.ReadCloser) io.ReadCloser {
97		if rc == nil {
98			return nil
99		}
100		if _, ok := rc.(*closeOnceReadCloser); ok {
101			return rc
102		}
103		return &closeOnceReadCloser{ReadCloser: rc}
104	}
